function clampInt(v, lo, hi) {
    const n = Number(v);
    if (!Number.isFinite(n)) return lo;
    return Math.max(lo, Math.min(hi, Math.floor(n)));
}

function maskFromCount(count, maxBits) {
    const c = clampInt(count, 0, maxBits);
    if (c <= 0) return 0;
    if (c >= maxBits) return (1 << maxBits) - 1;
    return (1 << c) - 1;
}

