}

const HYST_ON = 0.7;  // cool ON when temp > base + HYST_ON
const HYST_OFF = 0.4; // cool OFF when temp < base - HYST_OFF
const COOLDOWN_MS = 120000;

const last = flow.get("acAutoLastCmdAtMs");
if (typeof last === "number" && (now - last) < COOLDOWN_MS) {
    return null;
}

const coolingActive = d.acCoolingActive !== undefined ? !!d.acCoolingActive : !!d.fan;

let cmd = null;
if (!coolingActive) {
    if (temperature > baseSetpoint + HYST_ON) {
        // Lower setpoint to keep cooling active until we drop under base - HYST_OFF.
        cmd = { acMode: "auto", acSetpoint: baseSetpoint - HYST_OFF };
    }
} else {
    if (temperature < baseSetpoint - HYST_OFF) {
        // Raise setpoint to keep cooling inactive until we rise over base + HYST_ON.
        cmd = { acMode: "auto", acSetpoint: baseSetpoint + HYST_ON };
    }
}

if (!cmd) return null;

flow.set("acAutoLastCmdAtMs", now);
msg.payload = JSON.stringify(cmd);
return msg;

