let d = msg.payload;

let lightWatts = 15;
let fanWatts = 60;

let lastTs = context.get("lastTs") || Date.now();
let savedWh = context.get("savedWh") || 0;

let now = Date.now();
let dtHours = (now - lastTs) / 3600000;

if (!d.light) {
    savedWh += lightWatts * dtHours;
}

if (!d.fan) {
