        });
        req.setTimeout(26000, () => {
            req.destroy();
            if (!settled) {
                msg.payload = failPayload();
                settle();
            }
        });
        req.on("error", () => {
            if (!settled) {
                msg.payload = failPayload();
                settle();
            }
        });
        req.write(bodyStr);
        req.end();
    });
